class OAuth2Client {
  constructor(clientId, redirectUri) {
    this.clientId = clientId;
    this.redirectUri = redirectUri;
    this.accessToken = null;
  }

  authorize() {
    const authUrl = `https://authorization-server.com/oauth/authorize?response_type=token&client_id=${this.clientId}&redirect_uri=${encodeURIComponent(this.redirectUri)}&scope=read%20write`;
    window.location.href = authUrl;
  }

  parseAccessTokenFromUrl() {
    const urlParams = new URLSearchParams(window.location.hash.substring(1));
    if (urlParams.has('access_token')) {
      this.accessToken = urlParams.get('access_token');
      window.history.replaceState({}, document.title, window.location.pathname + window.location.search);
    }
  }

  async makeApiCall(endpoint) {
    if (!this.accessToken) {
      throw new Error('Access token not available');
    }

    const response = await fetch(endpoint, {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${this.accessToken}`
      }
    });

    if (!response.ok) {
      throw new Error(`API call failed with status ${response.status}`);
    }

    return await response.json();
  }
}

